{
  "name": "admin-theme",
  "displayName": "E-Menum Admin Theme",
  "version": "1.0.0",
  "description": "Professional admin panel theme for E-Menum platform with dark mode support, WCAG 2.1 AA compliance, and responsive design",
  "author": "E-Menum",
  "type": "admin",
  "enabled": true,
  "priority": 100,

  "layouts": {
    "default": "layouts/default.ejs",
    "auth": "layouts/auth.ejs"
  },

  "components": {
    "header": "components/header.ejs",
    "sidebar": "components/sidebar.ejs",
    "footer": "components/footer.ejs"
  },

  "partials": {
    "breadcrumb": "partials/breadcrumb.ejs",
    "alerts": "partials/alerts.ejs",
    "pagination": "partials/pagination.ejs"
  },

  "styles": {
    "main": "styles/main.css"
  },

  "assets": {
    "logo": {
      "light": "/images/logo-light.svg",
      "dark": "/images/logo-dark.svg"
    },
    "favicon": "/favicon.ico"
  },

  "features": {
    "darkMode": true,
    "rtlSupport": false,
    "responsive": true,
    "accessibility": {
      "wcagLevel": "AA",
      "highContrast": true,
      "reducedMotion": true
    }
  },

  "navigation": {
    "sidebar": {
      "collapsible": true,
      "defaultCollapsed": false,
      "hoverExpand": true,
      "icons": "phosphor"
    },
    "header": {
      "fixed": true,
      "showSearch": true,
      "showNotifications": true,
      "showUserMenu": true
    }
  },

  "colors": {
    "primary": "#2563eb",
    "primaryLight": "#3b82f6",
    "primaryDark": "#1d4ed8",
    "secondary": "#7c3aed",
    "accent": "#f59e0b"
  },

  "breakpoints": {
    "sm": "640px",
    "md": "768px",
    "lg": "1024px",
    "xl": "1280px",
    "2xl": "1536px"
  },

  "dependencies": {
    "css": ["tailwindcss"],
    "js": ["alpinejs"],
    "icons": ["phosphor-icons"]
  }
}
